16	const countLiveNeighbors = (cells: Set<string>): Map<string, number> => {
17	  const neighborCounts = new Map<string, number>();
18	  for (const cell of cells) {
19	    const [x, y] = parseCell(cell);
20	    for (let dx = -1; dx <= 1; dx++) {
21	      for (let dy = -1; dy <= 1; dy++) {
22	        if (dx === 0 && dy === 0) continue;
23	        const key = formatCell(x + dx, y + dy);
24	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
25	      }
26	    }
27	  }
28	  return neighborCounts;
29	};
30	
31	const cellLivesNextGeneration = (liveNeighborCount: number, isAlive: boolean): boolean =>
32	  liveNeighborCount === 3 || (liveNeighborCount === 2 && isAlive);
